parameters:
{
  "sources": {
    "posts": {
      "db": "stg",
      "table": "JsonPlaceholder_Posts",
      "business_keys": [
        "post_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND post_id IS NOT NULL"
      }
    },
    "comments": {
      "db": "stg",
      "table": "JsonPlaceholder_Comments",
      "business_keys": [
        "comment_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND comment_id IS NOT NULL AND post_id IS NOT NULL"
      }
    },
    "users": {
      "db": "stg",
      "table": "JsonPlaceholder_Users",
      "business_keys": [
        "user_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND user_id IS NOT NULL"
      }
    }
  },
  "target": {
    "db": "int",
    "table": "Blog_Post_Engagement",
    "business_keys": [
      "Post_ID"
    ],
    "write_mode": "truncate_insert"
  },
  "transformation": {
    "steps": [
      {
        "step_id": 10,
        "name": "read_posts",
        "type": "read_source",
        "config": {
          "source_name": "posts",
          "alias": "df_posts"
        }
      },
      {
        "step_id": 20,
        "name": "dedup_posts",
        "type": "deduplicate",
        "config": {
          "input_df": "df_posts",
          "alias": "df_posts_dedup",
          "use_source_business_keys": true,
          "source_name": "posts",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 30,
        "name": "read_comments",
        "type": "read_source",
        "config": {
          "source_name": "comments",
          "alias": "df_comments"
        }
      },
      {
        "step_id": 40,
        "name": "dedup_comments",
        "type": "deduplicate",
        "config": {
          "input_df": "df_comments",
          "alias": "df_comments_dedup",
          "use_source_business_keys": true,
          "source_name": "comments",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 50,
        "name": "aggregate_comment_counts",
        "type": "aggregate",
        "config": {
          "input_df": "df_comments_dedup",
          "alias": "df_comment_counts_raw",
          "group_by": [
            "post_id"
          ],
          "aggregations": [
            {
              "function": "count",
              "alias": "comment_count"
            }
          ]
        }
      },
      {
        "step_id": 60,
        "name": "rename_comment_counts",
        "type": "select",
        "config": {
          "input_df": "df_comment_counts_raw",
          "alias": "df_comment_counts",
          "columns": [
            {
              "expr": "post_id",
              "alias": "comment_post_id"
            },
            {
              "expr": "comment_count",
              "alias": "comment_count"
            }
          ]
        }
      },
      {
        "step_id": 70,
        "name": "read_users",
        "type": "read_source",
        "config": {
          "source_name": "users",
          "alias": "df_users"
        }
      },
      {
        "step_id": 80,
        "name": "dedup_users",
        "type": "deduplicate",
        "config": {
          "input_df": "df_users",
          "alias": "df_users_dedup",
          "use_source_business_keys": true,
          "source_name": "users",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 90,
        "name": "select_users",
        "type": "select",
        "config": {
          "input_df": "df_users_dedup",
          "alias": "df_users_sel",
          "columns": [
            {
              "expr": "user_id",
              "alias": "author_user_id_lookup"
            },
            {
              "expr": "display_name",
              "alias": "author_name"
            },
            {
              "expr": "username",
              "alias": "author_username"
            },
            {
              "expr": "email",
              "alias": "author_email"
            },
            {
              "expr": "company_name",
              "alias": "author_company_name"
            },
            {
              "expr": "address_city",
              "alias": "author_city"
            }
          ]
        }
      },
      {
        "step_id": 100,
        "name": "join_posts_to_comment_counts",
        "type": "join",
        "config": {
          "left_df": "df_posts_dedup",
          "right_df": "df_comment_counts",
          "alias": "df_post_comments",
          "join_type": "left",
          "on": [
            {
              "left": "post_id",
              "right": "comment_post_id"
            }
          ]
        }
      },
      {
        "step_id": 110,
        "name": "join_posts_to_users",
        "type": "join",
        "config": {
          "left_df": "df_post_comments",
          "right_df": "df_users_sel",
          "alias": "df_post_enriched",
          "join_type": "left",
          "on": [
            {
              "left": "author_user_id",
              "right": "author_user_id_lookup"
            }
          ]
        }
      },
      {
        "step_id": 120,
        "name": "select_blog_engagement",
        "type": "select",
        "config": {
          "input_df": "df_post_enriched",
          "alias": "df_selected",
          "columns": [
            {
              "expr": "post_id",
              "alias": "Post_ID"
            },
            {
              "expr": "author_user_id",
              "alias": "Author_User_ID"
            },
            {
              "expr": "author_name",
              "alias": "Author_Name"
            },
            {
              "expr": "author_username",
              "alias": "Author_Username"
            },
            {
              "expr": "author_email",
              "alias": "Author_Email"
            },
            {
              "expr": "author_company_name",
              "alias": "Author_Company_Name"
            },
            {
              "expr": "author_city",
              "alias": "Author_City"
            },
            {
              "expr": "post_title",
              "alias": "Post_Title"
            },
            {
              "expr": "post_body",
              "alias": "Post_Body"
            },
            {
              "expr": "coalesce(comment_count, 0)",
              "alias": "Comment_Count"
            },
            {
              "expr": "stg_load_date",
              "alias": "stg_load_date"
            },
            {
              "expr": "batch_id",
              "alias": "batch_id"
            }
          ]
        }
      },
      {
        "step_id": 130,
        "name": "add_system_fields",
        "type": "add_system_fields",
        "config": {
          "input_df": "df_selected",
          "alias": "df_with_sys"
        }
      },
      {
        "step_id": 140,
        "name": "compute_hash",
        "type": "compute_hash",
        "config": {
          "input_df": "df_with_sys",
          "alias": "df_hashed"
        }
      },
      {
        "step_id": 150,
        "name": "write_target",
        "type": "write_target",
        "config": {
          "input_df": "df_hashed"
        }
      }
    ]
  }
}
